// Lấy toàn bộ item input
const items = $input.all();

// Gom các mention-tag
const mentions = items
  .map(item => item.json.seatalk_id)
  .filter(id => id)
  .map(
    id => `<mention-tag target=\\\"seatalk://user?id=${id}\\\"/>`
  );

// Ghép thành 1 chuỗi xuống dòng (SeaTalk parse tốt nhất)
const content = mentions.join(' ');

// Trả ra 1 item
return [
  {
    json: {
      content,
    },
  },
];

// Lấy text gốc (đúng path theo ảnh)
const rawText = $json.candidates[0].content.parts[0].text;

// 1. Trích phần JSON {...} từ trong text
const match = rawText.match(/\{[\s\S]*?\}/);

if (!match) {
  throw new Error('Không tìm thấy JSON trong text');
}

// 2. Parse JSON
let data;
try {
  data = JSON.parse(match[0]);
} catch (e) {
  throw new Error('Parse JSON thất bại');
}

// 3. Map field (key tiếng Việt)
const orderId = data['Đơn hàng'] || null;
const details = data['Chi tiết'] || null;

// 4. Trả output
return [
  {
    json: {
      order_id: orderId,
      details: details
    }
  }
];

